CREATE FUNCTION app.authenticate_member_bearer_token(target_token_id app.short_id, target_token_hash text) RETURNS TABLE(member_id app.short_id)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'app', 'pg_temp'
    AS $$
begin
  return query
    update app.member_bearer_tokens mbt
       set last_used_at = case
         when mbt.last_used_at is null or mbt.last_used_at < now() - interval '5 minutes'
         then now()
         else mbt.last_used_at
       end
     where mbt.id = target_token_id
       and mbt.token_hash = target_token_hash
       and mbt.revoked_at is null
       and (mbt.expires_at is null or mbt.expires_at > now())
    returning mbt.member_id;
end;
$$;


CREATE FUNCTION app.consume_admission_challenge(target_challenge_id app.short_id, target_club_slug text, target_name text, target_email text, target_admission_details jsonb) RETURNS TABLE(admission_id app.short_id)
    LANGUAGE sql SECURITY DEFINER
    SET search_path TO 'app', 'pg_temp'
    AS $$
  with challenge as (
    delete from app.admission_challenges c
    where c.id = target_challenge_id
    returning 1
  ), target_club as (
    select c.id as club_id
    from app.clubs c
    where c.slug = target_club_slug
      and c.archived_at is null
    limit 1
  ), inserted as (
    insert into app.admissions (
      club_id, origin, applicant_email, applicant_name, admission_details
    )
    select
      target_club.club_id,
      'self_applied',
      target_email,
      target_name,
      target_admission_details
    from target_club
    where exists (select 1 from challenge)
    returning id as admission_id
  ), version_insert as (
    insert into app.admission_versions (
      admission_id, status, notes, version_no
    )
    select
      inserted.admission_id,
      'submitted',
      'Self-applied admission submitted after proof verification',
      1
    from inserted
  )
  select inserted.admission_id
  from inserted;
$$;


CREATE FUNCTION app.count_member_writes_today(target_member_id app.short_id, target_club_id app.short_id, target_action text) RETURNS integer
    LANGUAGE sql STABLE SECURITY DEFINER
    SET search_path TO 'app', 'pg_temp'
    AS $$
  select case target_action
    when 'entities.create' then (select count(*)::int from app.entities e where e.author_member_id = target_member_id and e.club_id = target_club_id and e.kind != 'event' and e.created_at >= current_date)
    when 'events.create' then (select count(*)::int from app.entities e where e.author_member_id = target_member_id and e.club_id = target_club_id and e.kind = 'event' and e.created_at >= current_date)
    when 'messages.send' then (select count(*)::int from app.transcript_messages tm join app.transcript_threads tt on tt.id = tm.thread_id where tm.sender_member_id = target_member_id and tt.club_id = target_club_id and tm.created_at >= current_date)
    else 0
  end
$$;


CREATE FUNCTION app.create_admission_challenge(target_difficulty integer, target_ttl_ms integer) RETURNS TABLE(challenge_id app.short_id, expires_at text)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'app', 'pg_temp'
    AS $$
begin
  delete from app.admission_challenges c
  where c.expires_at <= now();

  return query
    insert into app.admission_challenges (difficulty, expires_at)
    values (
      target_difficulty,
      now() + (target_ttl_ms * interval '1 millisecond')
    )
    returning
      id as challenge_id,
      admission_challenges.expires_at::text as expires_at;
end;
$$;


