CREATE FUNCTION app.sync_club_membership_compatibility_state() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare mirrored_left_at timestamptz;
begin
  mirrored_left_at := case when new.status in ('revoked', 'rejected') then new.created_at else null end;
  perform set_config('app.allow_club_membership_state_sync', '1', true);
  update app.club_memberships cm set status = new.status, left_at = mirrored_left_at where cm.id = new.membership_id;
  perform set_config('app.allow_club_membership_state_sync', '', true);
  return new;
exception when others then
  perform set_config('app.allow_club_membership_state_sync', '', true);
  raise;
end;
$$;


CREATE FUNCTION app.sync_club_owner_compatibility_state() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  perform set_config('app.allow_club_owner_sync', '1', true);
  update app.clubs c set owner_member_id = new.owner_member_id
   where c.id = new.club_id and c.owner_member_id is distinct from new.owner_member_id;
  perform set_config('app.allow_club_owner_sync', '', true);
  return new;
exception
  when others then
    perform set_config('app.allow_club_owner_sync', '', true);
    raise;
end;
$$;


SET default_tablespace = '';

SET default_table_access_method = heap;

CREATE TABLE app.club_membership_state_versions (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    membership_id app.short_id NOT NULL,
    status app.membership_state NOT NULL,
    reason text,
    version_no integer NOT NULL,
    supersedes_state_version_id app.short_id,
    source_transcript_thread_id app.short_id,
    source_transcript_message_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_member_id app.short_id,
    CONSTRAINT network_membership_state_versions_version_no_check CHECK ((version_no > 0))
);

ALTER TABLE ONLY app.club_membership_state_versions FORCE ROW LEVEL SECURITY;


CREATE TABLE app.club_memberships (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    club_id app.short_id NOT NULL,
    member_id app.short_id NOT NULL,
    sponsor_member_id app.short_id,
    role app.membership_role DEFAULT 'member'::app.membership_role NOT NULL,
    status app.membership_state DEFAULT 'active'::app.membership_state NOT NULL,
    joined_at timestamp with time zone DEFAULT now() NOT NULL,
    left_at timestamp with time zone,
    accepted_covenant_at timestamp with time zone,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    CONSTRAINT network_memberships_check CHECK ((((role = 'owner'::app.membership_role) AND (sponsor_member_id IS NULL)) OR ((role <> 'owner'::app.membership_role) AND (sponsor_member_id IS NOT NULL))))
);

ALTER TABLE ONLY app.club_memberships FORCE ROW LEVEL SECURITY;


CREATE VIEW app.current_club_membership_states AS
 SELECT DISTINCT ON (club_membership_state_versions.membership_id) club_membership_state_versions.id,
    club_membership_state_versions.membership_id,
    club_membership_state_versions.status,
    club_membership_state_versions.reason,
    club_membership_state_versions.version_no,
    club_membership_state_versions.supersedes_state_version_id,
    club_membership_state_versions.source_transcript_thread_id,
    club_membership_state_versions.source_transcript_message_id,
    club_membership_state_versions.created_at,
    club_membership_state_versions.created_by_member_id
   FROM app.club_membership_state_versions
  ORDER BY club_membership_state_versions.membership_id, club_membership_state_versions.version_no DESC, club_membership_state_versions.created_at DESC;


CREATE VIEW app.current_club_memberships AS
 SELECT cm.id,
    cm.club_id,
    cm.member_id,
    cm.sponsor_member_id,
    cm.role,
    ccms.status,
    cm.joined_at,
        CASE
            WHEN (ccms.status = ANY (ARRAY['revoked'::app.membership_state, 'rejected'::app.membership_state])) THEN ccms.created_at
            ELSE NULL::timestamp with time zone
        END AS left_at,
    cm.accepted_covenant_at,
    cm.metadata,
    ccms.id AS state_version_id,
    ccms.reason AS state_reason,
    ccms.version_no AS state_version_no,
    ccms.supersedes_state_version_id,
    ccms.source_transcript_thread_id,
    ccms.source_transcript_message_id,
    ccms.created_at AS state_created_at,
    ccms.created_by_member_id AS state_created_by_member_id
   FROM (app.club_memberships cm
     JOIN app.current_club_membership_states ccms ON (((ccms.membership_id)::text = (cm.id)::text)));


CREATE VIEW app.accessible_club_memberships AS
 SELECT ccm.id,
    ccm.club_id,
    ccm.member_id,
    ccm.sponsor_member_id,
    ccm.role,
    ccm.status,
    ccm.joined_at,
    ccm.left_at,
    ccm.accepted_covenant_at,
    ccm.metadata
   FROM app.current_club_memberships ccm
  WHERE ((ccm.status = 'active'::app.membership_state) AND (ccm.left_at IS NULL) AND ((ccm.role = 'owner'::app.membership_role) OR app.membership_has_live_subscription(ccm.id)));


CREATE VIEW app.active_club_memberships AS
 SELECT current_club_memberships.id,
    current_club_memberships.club_id,
    current_club_memberships.member_id,
    current_club_memberships.sponsor_member_id,
    current_club_memberships.role,
    current_club_memberships.status,
    current_club_memberships.joined_at,
    current_club_memberships.left_at,
    current_club_memberships.accepted_covenant_at,
    current_club_memberships.metadata,
    current_club_memberships.state_version_id,
    current_club_memberships.state_reason,
    current_club_memberships.state_version_no,
    current_club_memberships.supersedes_state_version_id,
    current_club_memberships.source_transcript_thread_id,
    current_club_memberships.source_transcript_message_id,
    current_club_memberships.state_created_at,
    current_club_memberships.state_created_by_member_id
   FROM app.current_club_memberships
  WHERE ((current_club_memberships.status = 'active'::app.membership_state) AND (current_club_memberships.left_at IS NULL));


CREATE TABLE app.admission_challenges (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    difficulty integer NOT NULL,
    expires_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT cold_application_challenges_check CHECK ((expires_at > created_at)),
    CONSTRAINT cold_application_challenges_difficulty_check CHECK ((difficulty > 0))
);

ALTER TABLE ONLY app.admission_challenges FORCE ROW LEVEL SECURITY;


CREATE TABLE app.admission_versions (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    admission_id app.short_id NOT NULL,
    status app.application_status NOT NULL,
    notes text,
    intake_kind text DEFAULT 'other'::text NOT NULL,
    intake_price_amount numeric(12,2),
    intake_price_currency text,
    intake_booking_url text,
    intake_booked_at timestamp with time zone,
    intake_completed_at timestamp with time zone,
    version_no integer NOT NULL,
    supersedes_version_id app.short_id,
    source_transcript_thread_id app.short_id,
    source_transcript_message_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_member_id app.short_id,
    CONSTRAINT application_versions_check CHECK (((intake_completed_at IS NULL) OR (intake_booked_at IS NULL) OR (intake_completed_at >= intake_booked_at))),
    CONSTRAINT application_versions_intake_kind_check CHECK ((intake_kind = ANY (ARRAY['fit_check'::text, 'advice_call'::text, 'other'::text]))),
    CONSTRAINT application_versions_intake_price_amount_check CHECK (((intake_price_amount IS NULL) OR (intake_price_amount >= (0)::numeric))),
    CONSTRAINT application_versions_intake_price_currency_check CHECK (((intake_price_currency IS NULL) OR (intake_price_currency ~ '^[A-Z]{3}$'::text))),
    CONSTRAINT application_versions_version_no_check CHECK ((version_no > 0))
);

ALTER TABLE ONLY app.admission_versions FORCE ROW LEVEL SECURITY;


CREATE TABLE app.admissions (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    club_id app.short_id NOT NULL,
    applicant_member_id app.short_id,
    sponsor_member_id app.short_id,
    membership_id app.short_id,
    origin text NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    applicant_email text,
    applicant_name text,
    admission_details jsonb DEFAULT '{}'::jsonb NOT NULL,
    CONSTRAINT admissions_origin_check CHECK ((origin = ANY (ARRAY['self_applied'::text, 'member_sponsored'::text, 'owner_nominated'::text]))),
    CONSTRAINT admissions_outsider_identity_check CHECK ((((origin = 'owner_nominated'::text) AND (applicant_member_id IS NOT NULL)) OR ((origin = ANY (ARRAY['self_applied'::text, 'member_sponsored'::text])) AND (applicant_email IS NOT NULL) AND (applicant_name IS NOT NULL) AND (length(btrim(applicant_email)) > 0) AND (length(btrim(applicant_name)) > 0))))
);

ALTER TABLE ONLY app.admissions FORCE ROW LEVEL SECURITY;


CREATE TABLE app.club_owner_versions (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    club_id app.short_id NOT NULL,
    owner_member_id app.short_id NOT NULL,
    version_no integer NOT NULL,
    supersedes_owner_version_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_member_id app.short_id,
