);

ALTER TABLE ONLY app.club_owner_versions FORCE ROW LEVEL SECURITY;


CREATE TABLE app.club_quota_policies (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    club_id app.short_id NOT NULL,
    action_name text NOT NULL,
    max_per_day integer NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT network_quota_policies_action_name_check CHECK ((action_name = ANY (ARRAY['entities.create'::text, 'events.create'::text, 'messages.send'::text]))),
    CONSTRAINT network_quota_policies_max_per_day_check CHECK ((max_per_day > 0))
);

ALTER TABLE ONLY app.club_quota_policies FORCE ROW LEVEL SECURITY;


CREATE TABLE app.clubs (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    slug text NOT NULL,
    name text NOT NULL,
    summary text,
    owner_member_id app.short_id NOT NULL,
    manifesto_markdown text,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    archived_at timestamp with time zone,
    publicly_listed boolean DEFAULT false NOT NULL,
    CONSTRAINT networks_name_check CHECK ((length(btrim(name)) > 0)),
    CONSTRAINT networks_slug_check CHECK ((slug ~ '^[a-z0-9]+(?:-[a-z0-9]+)*$'::text))
);

ALTER TABLE ONLY app.clubs FORCE ROW LEVEL SECURITY;


CREATE VIEW app.current_admission_versions AS
