    admission_versions.admission_id,
    admission_versions.status,
    admission_versions.notes,
    admission_versions.intake_kind,
    admission_versions.intake_price_amount,
    admission_versions.intake_price_currency,
    admission_versions.intake_booking_url,
    admission_versions.intake_booked_at,
    admission_versions.intake_completed_at,
    admission_versions.version_no,
    admission_versions.supersedes_version_id,
    admission_versions.source_transcript_thread_id,
    admission_versions.source_transcript_message_id,
    admission_versions.created_at,
    admission_versions.created_by_member_id
   FROM app.admission_versions
  ORDER BY admission_versions.admission_id, admission_versions.version_no DESC, admission_versions.created_at DESC;


CREATE VIEW app.current_admissions AS
 SELECT a.id,
    a.club_id,
    a.applicant_member_id,
    a.sponsor_member_id,
    a.membership_id,
    a.origin,
    a.admission_details,
    a.metadata,
    a.created_at,
    cav.id AS version_id,
    cav.status,
    cav.notes,
    cav.intake_kind,
    cav.intake_price_amount,
    cav.intake_price_currency,
    cav.intake_booking_url,
    cav.intake_booked_at,
    cav.intake_completed_at,
    cav.version_no,
    cav.supersedes_version_id,
    cav.source_transcript_thread_id,
    cav.source_transcript_message_id,
    cav.created_at AS version_created_at,
    cav.created_by_member_id AS version_created_by_member_id,
    a.applicant_email,
    a.applicant_name
   FROM (app.admissions a
     JOIN app.current_admission_versions cav ON (((cav.admission_id)::text = (a.id)::text)));


CREATE VIEW app.current_club_owners AS
