CREATE TABLE app.member_updates (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    stream_seq bigint NOT NULL,
    recipient_member_id app.short_id NOT NULL,
    club_id app.short_id NOT NULL,
    topic text NOT NULL,
    payload jsonb DEFAULT '{}'::jsonb NOT NULL,
    entity_id app.short_id,
    entity_version_id app.short_id,
    transcript_message_id app.short_id,
    created_by_member_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT member_updates_check CHECK (((transcript_message_id IS NOT NULL) OR ((entity_id IS NOT NULL) AND (entity_version_id IS NOT NULL)) OR (payload <> '{}'::jsonb))),
    CONSTRAINT member_updates_topic_check CHECK ((length(btrim(topic)) > 0))
);

ALTER TABLE ONLY app.member_updates FORCE ROW LEVEL SECURITY;


CREATE VIEW app.pending_member_updates AS
 SELECT mu.id AS update_id,
    mu.stream_seq,
    mu.recipient_member_id,
    mu.club_id,
    mu.topic,
    mu.payload,
    mu.entity_id,
    mu.entity_version_id,
    mu.transcript_message_id,
    mu.created_by_member_id,
    mu.created_at
   FROM (app.member_updates mu
     LEFT JOIN app.current_member_update_receipts cmur ON ((((cmur.member_update_id)::text = (mu.id)::text) AND ((cmur.recipient_member_id)::text = (mu.recipient_member_id)::text))))
  WHERE (cmur.id IS NULL);


CREATE TABLE app.transcript_messages (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    thread_id app.short_id NOT NULL,
    sender_member_id app.short_id,
    role app.transcript_role NOT NULL,
    message_text text,
    payload jsonb DEFAULT '{}'::jsonb NOT NULL,
    in_reply_to_message_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT transcript_messages_check CHECK (((message_text IS NOT NULL) OR (payload <> '{}'::jsonb)))
);

ALTER TABLE ONLY app.transcript_messages FORCE ROW LEVEL SECURITY;


CREATE TABLE app.transcript_threads (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    club_id app.short_id,
    kind app.transcript_thread_kind NOT NULL,
    created_by_member_id app.short_id,
    counterpart_member_id app.short_id,
    subject_entity_id app.short_id,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    archived_at timestamp with time zone
);

ALTER TABLE ONLY app.transcript_threads FORCE ROW LEVEL SECURITY;


CREATE VIEW app.current_dm_inbox_threads AS
 WITH thread_messages AS (
         SELECT tt.id AS thread_id,
            tt.club_id,
            participant.recipient_member_id,
                CASE
                    WHEN ((tt.created_by_member_id)::text = (participant.recipient_member_id)::text) THEN tt.counterpart_member_id
                    ELSE tt.created_by_member_id
                END AS counterpart_member_id,
            tm_1.id AS message_id,
            tm_1.sender_member_id,
            tm_1.role,
            tm_1.message_text,
            tm_1.created_at,
            row_number() OVER (PARTITION BY participant.recipient_member_id, tt.id ORDER BY tm_1.created_at DESC, tm_1.id DESC) AS latest_row_no
           FROM ((app.transcript_threads tt
             JOIN ( SELECT tt_inner.id AS thread_id,
                    tt_inner.created_by_member_id AS recipient_member_id
                   FROM app.transcript_threads tt_inner
                  WHERE ((tt_inner.kind = 'dm'::app.transcript_thread_kind) AND (tt_inner.archived_at IS NULL) AND (tt_inner.created_by_member_id IS NOT NULL))
                UNION
                 SELECT tt_inner.id AS thread_id,
                    tt_inner.counterpart_member_id AS recipient_member_id
                   FROM app.transcript_threads tt_inner
                  WHERE ((tt_inner.kind = 'dm'::app.transcript_thread_kind) AND (tt_inner.archived_at IS NULL) AND (tt_inner.counterpart_member_id IS NOT NULL))) participant ON (((participant.thread_id)::text = (tt.id)::text)))
             JOIN app.transcript_messages tm_1 ON (((tm_1.thread_id)::text = (tt.id)::text)))
          WHERE ((tt.kind = 'dm'::app.transcript_thread_kind) AND (tt.archived_at IS NULL))
        ), unread_messages AS (
         SELECT pmu.recipient_member_id,
            tm_1.thread_id,
            (count(DISTINCT pmu.transcript_message_id))::integer AS unread_message_count,
            (count(*))::integer AS unread_update_count,
            max(tm_1.created_at) AS latest_unread_message_created_at
           FROM ((app.pending_member_updates pmu
             JOIN app.transcript_messages tm_1 ON (((tm_1.id)::text = (pmu.transcript_message_id)::text)))
             JOIN app.transcript_threads tt ON (((tt.id)::text = (tm_1.thread_id)::text)))
          WHERE ((pmu.topic = 'transcript.message.created'::text) AND (pmu.transcript_message_id IS NOT NULL) AND (tt.kind = 'dm'::app.transcript_thread_kind) AND (tt.archived_at IS NULL))
          GROUP BY pmu.recipient_member_id, tm_1.thread_id
        )
 SELECT tm.recipient_member_id,
    tm.club_id,
    tm.thread_id,
    tm.counterpart_member_id,
    tm.message_id AS latest_message_id,
    tm.sender_member_id AS latest_sender_member_id,
    tm.role AS latest_role,
    tm.message_text AS latest_message_text,
    tm.created_at AS latest_created_at,
    COALESCE(um.unread_message_count, 0) AS unread_message_count,
    COALESCE(um.unread_update_count, 0) AS unread_update_count,
    um.latest_unread_message_created_at,
    (COALESCE(um.unread_message_count, 0) > 0) AS has_unread
   FROM (thread_messages tm
     LEFT JOIN unread_messages um ON ((((um.recipient_member_id)::text = (tm.recipient_member_id)::text) AND ((um.thread_id)::text = (tm.thread_id)::text))))
  WHERE (tm.latest_row_no = 1);


CREATE VIEW app.current_dm_thread_participants AS
 SELECT tt.id AS thread_id,
    tt.club_id AS network_id,
    tt.created_by_member_id AS participant_member_id,
    tt.counterpart_member_id
   FROM app.transcript_threads tt
  WHERE ((tt.kind = 'dm'::app.transcript_thread_kind) AND (tt.archived_at IS NULL) AND (tt.created_by_member_id IS NOT NULL) AND (tt.counterpart_member_id IS NOT NULL))
UNION ALL
 SELECT tt.id AS thread_id,
    tt.club_id AS network_id,
    tt.counterpart_member_id AS participant_member_id,
    tt.created_by_member_id AS counterpart_member_id
   FROM app.transcript_threads tt
  WHERE ((tt.kind = 'dm'::app.transcript_thread_kind) AND (tt.archived_at IS NULL) AND (tt.created_by_member_id IS NOT NULL) AND (tt.counterpart_member_id IS NOT NULL));


CREATE TABLE app.embeddings (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    member_profile_version_id app.short_id,
    entity_version_id app.short_id,
    transcript_message_id app.short_id,
    model text NOT NULL,
    dimensions integer NOT NULL,
    embedding double precision[] NOT NULL,
    source_text text NOT NULL,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT embeddings_check CHECK ((((((member_profile_version_id IS NOT NULL))::integer + ((entity_version_id IS NOT NULL))::integer) + ((transcript_message_id IS NOT NULL))::integer) = 1)),
    CONSTRAINT embeddings_check1 CHECK ((array_length(embedding, 1) = dimensions)),
    CONSTRAINT embeddings_dimensions_check CHECK ((dimensions > 0))
);

ALTER TABLE ONLY app.embeddings FORCE ROW LEVEL SECURITY;


CREATE VIEW app.current_entity_version_embeddings AS
 SELECT DISTINCT ON (e.entity_version_id) e.id,
    e.entity_version_id,
    e.model,
    e.dimensions,
    e.source_text,
    e.metadata,
    e.created_at
   FROM app.embeddings e
  WHERE (e.entity_version_id IS NOT NULL)
  ORDER BY e.entity_version_id, e.created_at DESC, e.id DESC;


CREATE TABLE app.entity_versions (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    entity_id app.short_id NOT NULL,
    version_no integer NOT NULL,
    state app.entity_state DEFAULT 'published'::app.entity_state NOT NULL,
    title text,
    summary text,
    body text,
    work_mode app.work_mode DEFAULT 'unspecified'::app.work_mode NOT NULL,
    compensation app.compensation_kind DEFAULT 'unspecified'::app.compensation_kind NOT NULL,
    starts_at timestamp with time zone,
    ends_at timestamp with time zone,
    timezone text,
    recurrence_rule text,
    capacity integer,
    effective_at timestamp with time zone DEFAULT now() NOT NULL,
    expires_at timestamp with time zone,
    content jsonb DEFAULT '{}'::jsonb NOT NULL,
    source_transcript_thread_id app.short_id,
    source_transcript_message_id app.short_id,
    supersedes_version_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_member_id app.short_id,
    CONSTRAINT entity_versions_capacity_check CHECK (((capacity IS NULL) OR (capacity > 0))),
    CONSTRAINT entity_versions_check CHECK (((ends_at IS NULL) OR (starts_at IS NULL) OR (ends_at >= starts_at))),
    CONSTRAINT entity_versions_check1 CHECK (((expires_at IS NULL) OR (expires_at >= effective_at))),
    CONSTRAINT entity_versions_version_no_check CHECK ((version_no > 0))
);

ALTER TABLE ONLY app.entity_versions FORCE ROW LEVEL SECURITY;


CREATE VIEW app.current_entity_versions AS
 SELECT DISTINCT ON (entity_versions.entity_id) entity_versions.id,
    entity_versions.entity_id,
    entity_versions.version_no,
    entity_versions.state,
    entity_versions.title,
    entity_versions.summary,
    entity_versions.body,
    entity_versions.work_mode,
    entity_versions.compensation,
    entity_versions.starts_at,
    entity_versions.ends_at,
    entity_versions.timezone,
    entity_versions.recurrence_rule,
    entity_versions.capacity,
    entity_versions.effective_at,
    entity_versions.expires_at,
    entity_versions.content,
    entity_versions.source_transcript_thread_id,
    entity_versions.source_transcript_message_id,
    entity_versions.supersedes_version_id,
    entity_versions.created_at,
    entity_versions.created_by_member_id
   FROM app.entity_versions
  ORDER BY entity_versions.entity_id, entity_versions.version_no DESC, entity_versions.created_at DESC;


