CREATE TABLE app.member_profile_versions (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    member_id app.short_id NOT NULL,
    version_no integer NOT NULL,
    display_name text NOT NULL,
    tagline text,
    summary text,
    what_i_do text,
    known_for text,
    services_summary text,
    website_url text,
    links jsonb DEFAULT '[]'::jsonb NOT NULL,
    profile jsonb DEFAULT '{}'::jsonb NOT NULL,
    source_transcript_thread_id app.short_id,
    source_transcript_message_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    created_by_member_id app.short_id,
