    CONSTRAINT member_profile_versions_version_no_check CHECK ((version_no > 0))
);

ALTER TABLE ONLY app.member_profile_versions FORCE ROW LEVEL SECURITY;


CREATE VIEW app.current_member_profiles AS
 SELECT DISTINCT ON (member_profile_versions.member_id) member_profile_versions.id,
    member_profile_versions.member_id,
    member_profile_versions.version_no,
    member_profile_versions.display_name,
    member_profile_versions.tagline,
    member_profile_versions.summary,
    member_profile_versions.what_i_do,
    member_profile_versions.known_for,
    member_profile_versions.services_summary,
    member_profile_versions.website_url,
    member_profile_versions.links,
    member_profile_versions.profile,
    member_profile_versions.source_transcript_thread_id,
    member_profile_versions.source_transcript_message_id,
    member_profile_versions.created_at,
    member_profile_versions.created_by_member_id
   FROM app.member_profile_versions
  ORDER BY member_profile_versions.member_id, member_profile_versions.version_no DESC, member_profile_versions.created_at DESC;


CREATE VIEW app.current_profile_version_embeddings AS
 SELECT DISTINCT ON (e.member_profile_version_id) e.id,
    e.member_profile_version_id,
    e.model,
    e.dimensions,
    e.source_text,
    e.metadata,
    e.created_at
   FROM app.embeddings e
  WHERE (e.member_profile_version_id IS NOT NULL)
  ORDER BY e.member_profile_version_id, e.created_at DESC, e.id DESC;


CREATE VIEW app.current_published_entity_versions AS
 SELECT current_entity_versions.id,
    current_entity_versions.entity_id,
    current_entity_versions.version_no,
    current_entity_versions.state,
    current_entity_versions.title,
    current_entity_versions.summary,
    current_entity_versions.body,
    current_entity_versions.work_mode,
    current_entity_versions.compensation,
    current_entity_versions.starts_at,
    current_entity_versions.ends_at,
    current_entity_versions.timezone,
    current_entity_versions.recurrence_rule,
    current_entity_versions.capacity,
    current_entity_versions.effective_at,
    current_entity_versions.expires_at,
    current_entity_versions.content,
    current_entity_versions.source_transcript_thread_id,
    current_entity_versions.source_transcript_message_id,
    current_entity_versions.supersedes_version_id,
    current_entity_versions.created_at,
    current_entity_versions.created_by_member_id
   FROM app.current_entity_versions
  WHERE (current_entity_versions.state = 'published'::app.entity_state);


CREATE TABLE app.edges (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    club_id app.short_id,
    kind app.edge_kind NOT NULL,
    from_member_id app.short_id,
    from_entity_id app.short_id,
    from_entity_version_id app.short_id,
    to_member_id app.short_id,
    to_entity_id app.short_id,
    to_entity_version_id app.short_id,
    reason text,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    source_transcript_message_id app.short_id,
    created_by_member_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    archived_at timestamp with time zone,
    CONSTRAINT edges_check CHECK ((((((from_member_id IS NOT NULL))::integer + ((from_entity_id IS NOT NULL))::integer) + ((from_entity_version_id IS NOT NULL))::integer) = 1)),
    CONSTRAINT edges_check2 CHECK (((kind <> 'vouched_for'::app.edge_kind) OR ((from_member_id IS NOT NULL) AND (to_member_id IS NOT NULL) AND (reason IS NOT NULL)))),
    CONSTRAINT edges_no_self_vouch CHECK (((kind <> 'vouched_for'::app.edge_kind) OR ((from_member_id)::text <> (to_member_id)::text))),
    CONSTRAINT edges_target_check CHECK ((((((to_member_id IS NOT NULL))::integer + ((to_entity_id IS NOT NULL))::integer) + ((to_entity_version_id IS NOT NULL))::integer) = 1))
);

ALTER TABLE ONLY app.edges FORCE ROW LEVEL SECURITY;


CREATE TABLE app.entities (
    id app.short_id DEFAULT app.new_id() NOT NULL,
    club_id app.short_id NOT NULL,
    kind app.entity_kind NOT NULL,
    author_member_id app.short_id NOT NULL,
    parent_entity_id app.short_id,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    archived_at timestamp with time zone,
    deleted_at timestamp with time zone,
    metadata jsonb DEFAULT '{}'::jsonb NOT NULL,
    CONSTRAINT entities_check CHECK ((((kind = 'comment'::app.entity_kind) AND (parent_entity_id IS NOT NULL)) OR (kind <> 'comment'::app.entity_kind)))
);

ALTER TABLE ONLY app.entities FORCE ROW LEVEL SECURITY;


CREATE VIEW app.live_entities AS
 SELECT e.id AS entity_id,
    e.club_id,
    e.kind,
    e.author_member_id,
    e.parent_entity_id,
    e.created_at AS entity_created_at,
    cev.id AS entity_version_id,
    cev.version_no,
    cev.state,
    cev.title,
    cev.summary,
    cev.body,
    cev.work_mode,
    cev.compensation,
    cev.starts_at,
    cev.ends_at,
    cev.timezone,
    cev.recurrence_rule,
    cev.capacity,
    cev.effective_at,
    cev.expires_at,
    cev.content,
    cev.created_at AS version_created_at,
    cev.created_by_member_id
   FROM (app.entities e
     JOIN app.current_published_entity_versions cev ON (((cev.entity_id)::text = (e.id)::text)))
  WHERE ((e.archived_at IS NULL) AND (e.deleted_at IS NULL) AND ((cev.expires_at IS NULL) OR (cev.expires_at > now())));


