CREATE POLICY members_insert_definer ON app.members FOR INSERT WITH CHECK ((CURRENT_USER = 'clawclub_security_definer_owner'::name));


CREATE POLICY members_select_actor_scope ON app.members FOR SELECT USING (app.actor_can_access_member(id));


CREATE POLICY members_select_definer ON app.members FOR SELECT USING ((CURRENT_USER = 'clawclub_security_definer_owner'::name));


CREATE POLICY members_select_security_definer_owner ON app.members FOR SELECT USING ((CURRENT_USER = 'clawclub_security_definer_owner'::name));


CREATE POLICY members_update_self ON app.members FOR UPDATE USING ((((id)::text = (app.current_actor_member_id())::text) OR app.current_actor_is_superadmin())) WITH CHECK ((((id)::text = (app.current_actor_member_id())::text) OR app.current_actor_is_superadmin()));


ALTER TABLE app.subscriptions ENABLE ROW LEVEL SECURITY;

CREATE POLICY subscriptions_delete_none ON app.subscriptions FOR DELETE USING (false);


CREATE POLICY subscriptions_insert_superadmin ON app.subscriptions FOR INSERT WITH CHECK (app.current_actor_is_superadmin());


CREATE POLICY subscriptions_select_actor_scope ON app.subscriptions FOR SELECT USING ((((payer_member_id)::text = (app.current_actor_member_id())::text) OR app.current_actor_is_superadmin() OR app.membership_belongs_to_current_actor(membership_id)));


CREATE POLICY subscriptions_select_security_definer_owner ON app.subscriptions FOR SELECT USING ((CURRENT_USER = 'clawclub_security_definer_owner'::name));


CREATE POLICY subscriptions_update_superadmin ON app.subscriptions FOR UPDATE USING (app.current_actor_is_superadmin()) WITH CHECK (app.current_actor_is_superadmin());


CREATE POLICY superadmin_select_club_quota_policies ON app.club_quota_policies FOR SELECT USING (((current_setting('app.actor_member_id'::text, true) IS NOT NULL) AND (EXISTS ( SELECT 1
   FROM app.current_member_global_roles cmgr
  WHERE (((cmgr.member_id)::text = ((current_setting('app.actor_member_id'::text, true))::app.short_id)::text) AND (cmgr.role = 'superadmin'::app.global_role))))));


ALTER TABLE app.transcript_messages ENABLE ROW LEVEL SECURITY;

CREATE POLICY transcript_messages_insert_thread_scope ON app.transcript_messages FOR INSERT WITH CHECK (((role = 'member'::app.transcript_role) AND ((sender_member_id)::text = (app.current_actor_member_id())::text) AND app.actor_can_access_thread(thread_id)));


CREATE POLICY transcript_messages_select_superadmin ON app.transcript_messages FOR SELECT USING (app.current_actor_is_superadmin());


CREATE POLICY transcript_messages_select_thread_scope ON app.transcript_messages FOR SELECT USING (app.actor_can_access_thread(thread_id));


ALTER TABLE app.transcript_threads ENABLE ROW LEVEL SECURITY;

CREATE POLICY transcript_threads_insert_participant_scope ON app.transcript_threads FOR INSERT WITH CHECK (((archived_at IS NULL) AND (kind = 'dm'::app.transcript_thread_kind) AND ((created_by_member_id)::text = (app.current_actor_member_id())::text) AND (counterpart_member_id IS NOT NULL) AND app.actor_has_club_access(club_id)));


CREATE POLICY transcript_threads_select_participant_scope ON app.transcript_threads FOR SELECT USING (((archived_at IS NULL) AND app.actor_has_club_access(club_id) AND (((app.current_actor_member_id())::text = (created_by_member_id)::text) OR ((app.current_actor_member_id())::text = (counterpart_member_id)::text))));


CREATE POLICY transcript_threads_select_superadmin ON app.transcript_threads FOR SELECT USING (app.current_actor_is_superadmin());


